import java.io.File;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    public void testPrintCreatesCSVPrinterSuccessfully() throws IOException {
        try (MockedConstruction<OutputStreamWriter> mockedOutputStreamWriter = mockConstruction(OutputStreamWriter.class);
             MockedConstruction<CSVPrinter> mockedCSVPrinter = mockConstruction(CSVPrinter.class)) {

            CSVPrinter printer = csvFormat.print(mockFile, charset);

            assertNotNull(printer);
            // Verify that OutputStreamWriter constructed with FileOutputStream and charset
            assertEquals(1, mockedOutputStreamWriter.constructed().size());
            assertEquals(1, mockedCSVPrinter.constructed().size());

            OutputStreamWriter osw = mockedOutputStreamWriter.constructed().get(0);
            CSVPrinter csvPrinter = mockedCSVPrinter.constructed().get(0);

            // The returned printer should be the mocked CSVPrinter instance
            assertSame(csvPrinter, printer);
        }
    }

    @Test
    public void testPrintThrowsIOExceptionWhenFileOutputStreamFails() {
        // We cannot mock FileOutputStream constructor easily without a framework like PowerMock,
        // so we simulate by passing a file that cannot be written to.

        File nonWritableFile = new File("/root/forbiddenfile.csv");
        // Using a charset that should be valid
        Charset charset = Charset.forName("UTF-8");

        // We expect IOException due to inability to open FileOutputStream on this file path
        assertThrows(IOException.class, () -> csvFormat.print(nonWritableFile, charset));
    }

    @Test
    public void testPrintThrowsNullPointerExceptionWhenFileIsNull() {
        assertThrows(NullPointerException.class, () -> csvFormat.print(null, charset));
    }

    @Test
    public void testPrintThrowsNullPointerExceptionWhenCharsetIsNull() {
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }
}
